import{_ as t,c as a,o as r,a2 as i}from"./chunks/framework.CIiVzG-O.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1783607180000}'),o={name:"guide/introduction.md"};function n(s,e,l,c,p,u){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="about-nuezip" tabindex="-1">About NueZip <a class="header-anchor" href="#about-nuezip" aria-label="Permalink to &quot;About NueZip&quot;">​</a></h2><p>NueZip is a professional archive manager for macOS, designed for speed, reliability, and ease of use. Whether you need to compress files, extract archives, convert formats, or manage password-protected archives, NueZip handles it all with a native macOS experience.</p><p>Built with Swift 6 and SwiftUI, NueZip takes full advantage of Apple Silicon and macOS technologies to deliver a fast, lightweight, and secure archive management tool.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><h3 id="📦-multi-format-support" tabindex="-1">📦 <strong>Multi-Format Support</strong> <a class="header-anchor" href="#📦-multi-format-support" aria-label="Permalink to &quot;📦 **Multi-Format Support**&quot;">​</a></h3><p>NueZip supports all major archive formats:</p><ul><li><strong>RAR</strong> — Read-only with multi-volume support</li><li><strong>ZIP</strong> — Universal compression with AES encryption</li><li><strong>7-Zip</strong> — High-compression ratio with LZMA2</li><li><strong>TAR</strong> — Archive bundling with optional GZIP/BZIP2</li><li><strong>GZIP / BZIP2</strong> — Standalone compression formats</li></ul><h3 id="⚡-fast-extraction" tabindex="-1">⚡ <strong>Fast Extraction</strong> <a class="header-anchor" href="#⚡-fast-extraction" aria-label="Permalink to &quot;⚡ **Fast Extraction**&quot;">​</a></h3><p>Dual-engine architecture selects the optimal backend for each format, ensuring the fastest possible extraction speeds.</p><h3 id="🔐-password-protection-encryption" tabindex="-1">🔐 <strong>Password Protection &amp; Encryption</strong> <a class="header-anchor" href="#🔐-password-protection-encryption" aria-label="Permalink to &quot;🔐 **Password Protection &amp; Encryption**&quot;">​</a></h3><p>Create password-protected archives with industry-standard encryption. Built-in password manager stores credentials securely in your local keychain.</p><h3 id="📋-batch-operations" tabindex="-1">📋 <strong>Batch Operations</strong> <a class="header-anchor" href="#📋-batch-operations" aria-label="Permalink to &quot;📋 **Batch Operations**&quot;">​</a></h3><p>Process multiple files at once:</p><ul><li><strong>Batch Compress</strong> — Compress multiple items into individual archives</li><li><strong>Batch Extract</strong> — Extract multiple archives simultaneously</li><li><strong>Batch Convert</strong> — Convert archives between formats in bulk</li><li><strong>Batch Encrypt</strong> — Apply password protection to multiple archives</li></ul><h3 id="🛠️-advanced-tools" tabindex="-1">🛠️ <strong>Advanced Tools</strong> <a class="header-anchor" href="#🛠️-advanced-tools" aria-label="Permalink to &quot;🛠️ **Advanced Tools**&quot;">​</a></h3><ul><li><strong>Archive Repair</strong> — Fix corrupted RAR and ZIP archives</li><li><strong>Format Conversion</strong> — Convert between any supported formats</li><li><strong>Performance Benchmark</strong> — Test compression speed and rating</li><li><strong>Archive Search</strong> — Find files within archives by name</li><li><strong>File Info Viewer</strong> — View detailed metadata for archive entries</li><li><strong>Volume/Split Support</strong> — Create multi-volume archives</li></ul><h3 id="🖥️-native-macos-experience" tabindex="-1">🖥️ <strong>Native macOS Experience</strong> <a class="header-anchor" href="#🖥️-native-macos-experience" aria-label="Permalink to &quot;🖥️ **Native macOS Experience**&quot;">​</a></h3><ul><li><strong>Swift 6 + SwiftUI</strong> — Modern, responsive interface</li><li><strong>Apple Silicon Native</strong> — Optimized for M-series chips</li><li><strong>Finder Integration</strong> — Right-click context menu extension</li><li><strong>Drag &amp; Drop</strong> — Quick access via menu bar drop panel</li><li><strong>Minimal Resource Usage</strong> — Lightweight background operation</li></ul><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><ul><li><strong>Operating System</strong>: macOS 14 Sonoma or later</li><li><strong>CPU</strong>: Apple Silicon (M-series) or Intel (64-bit)</li><li><strong>Memory</strong>: 4GB RAM minimum, 8GB recommended</li><li><strong>Storage</strong>: ~50 MB for installation</li></ul><h2 id="supported-languages" tabindex="-1">Supported Languages <a class="header-anchor" href="#supported-languages" aria-label="Permalink to &quot;Supported Languages&quot;">​</a></h2><p>NueZip supports English, Chinese (Simplified), Chinese (Traditional), Japanese, Korean, and many other languages.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>If you&#39;re new to NueZip, start with the <a href="/guide/installation.html">Installation Guide</a> to get the application running on your Mac.</p>',25)])])}const g=t(o,[["render",n]]);export{h as __pageData,g as default};
